var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이런, 왼쪽 다리가 또 맛이 가 버렸네.","JPN":"おっと、左足がまた壊れちまったみたいだな。","ENG":"Uh-oh, my left leg is acting up again.","TWN":"該死！左腳又不給力了！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"서브스톰에 가는 대로 신품으로 다시 맞춰야겠어.","JPN":"サブストームに着いたら新品に取り替えないと。","ENG":"I'd better get a new one as soon as I'm back in Substorm.","TWN":"等回到次級風暴後又要買新的來換了！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"깡통, 아까 여자애가 쏜 탄환 말이야. 두목이 머리 뺏길 때 당했던 거 맞지?","JPN":"ボロ缶、さっきの女の子が撃った弾丸なんだけど。ボスが頭部を奪われた時にやられたものと一緒だったよな？","ENG":"Tin Can, about the bullet that the girl fired at us. It's the same one that cost the Boss's head, isn't it?","TWN":"鐵桶，剛剛那個女生發射的彈藥，就是老大頭被搶走時打中的那個吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그래. 격발 시 흡수한 카운터의 CRF를 강력한 전자기 펄스로 변환하는 탄환이다.","JPN":"ああ。撃発時に吸収したカウンターのCRFを強力な電子パルスに変換する弾丸だ。","ENG":"Yes. It feeds on Counters' CRF and releases a powerful EMP when fired.","TWN":"沒錯，那個彈藥會在爆炸時，將吸收的制裁者CRF，轉換成強烈的電磁脈衝。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그 때는 그걸 함대 규모의 포격으로 쏟아부었으니까.","JPN":"あの時は、それを艦隊規模の砲撃でぶち込んできたからな。","ENG":"At that time, the Coalition Fleet showered us with those bullets.","TWN":"而那時候那個彈藥是以艦隊規模在發射的，量之龐大。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"알파트릭스 놈들이 직접 칼을 빼들었는데 잡담이 잘도 나오나 보군.","JPN":"アルファトリックスの連中が本腰を入れて来たのに、よくそんな呑気に雑談できるな。","ENG":"Alphatrix has stepped in, and you're chatting as if everything's just peachy.","TWN":"阿爾法崔克斯的人親自介入了，看來應該是有收到風聲。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"목적지까진 얼마나 남았지?","JPN":"目的地まではあとどれくらいだ？","ENG":"How far are we from our destination now?","TWN":"距離目的地還有多遠？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"목적지인 서브스톰까지 앞으로 약 30분.","JPN":"目的地のサブストームまで残り約30分。","ENG":"Thirty minutes left until Substorm.","TWN":"距離目的地次級風暴還有30分鐘左右。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"다이브 신호는 더 이상 안 잡혀. 포기한 모양인데?","JPN":"ダイブ信号はこれ以上確認されない。諦めたかもな？","ENG":"I'm not getting any more Dive signals. They must have given up.","TWN":"而且沒有再收到躍入訊號咧？是放棄了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"……라고 말씀드리는 순간, 빌어먹을 다이브 신호 포착!","JPN":"……と言った瞬間、ちくしょう、ダイブ信号捕捉！","ENG":"... No! Dammit, we're getting new Dive signals!","TWN":"……就在這個瞬間，又收到該死的躍入訊號囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"끈질기군. 다이브 포인트는 어디지?","JPN":"しつこいな。ダイブポイントはどこだ？","ENG":"How persistent! Where's the Dive point?","TWN":"有夠纏人的！ 躍入點在哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어, 그러니까 그게……","JPN":"あ、えーと、それが……","ENG":"Err, that's... Mm...","TWN":"嗯…就是在……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"……머리 위?","JPN":"……頭の上？","ENG":"Above our heads?","TWN":"……頭上方？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"스캐빈저 함선 발견. 육안으로 보일 정도로 가깝습니다.","JPN":"スカベンジャー艦船発見。肉眼で見えるほど近いです。","ENG":"We've found the Scavenger ship. It's close enough to see with the naked eye.","TWN":"發現清道夫艦船，就在肉眼可見的距離內！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"실장님 말씀이 맞았군요. 침식파장이 가장 강한 곳에 숨어 있었어요.","JPN":"室長のおっしゃったとおりですね。侵食波長が最も強いところに隠れていました。","ENG":"Chief, you were right. They've been hiding where Corruption waves are at their strongest.","TWN":"室長說的沒錯！他們果然躲在侵蝕波最強的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"놈들은 이제 독 안에 든 쥐나 다름없습니다.","JPN":"やつらはもう袋のネズミ同然です。","ENG":"Now, they're just as good as dead.","TWN":"那傢伙現在與甕中之鱉無異！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATADOR_SHIP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"공치사는 나중에 하죠.","JPN":"空世辞は後にしましょう。","ENG":"We'll celebrate later.","TWN":"歌功頌德的話等之後再說吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"주포 준비. 놈들이 다이브를 시도하기 전에 공격해야 합니다.","JPN":"主砲準備。連中がダイブする前に攻撃します。","ENG":"Prepare the main cannon. We must attack them before they attempt another Dive.","TWN":"主砲預備！必須在那些傢伙嘗試躍入前攻擊他們！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"알겠습니다!","JPN":"了解いたしました！","ENG":"Yes, ma'am!","TWN":"遵命！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"……엇?","JPN":"……あれ？","ENG":"Err?","TWN":"……嗯？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"실장님! 적 함선이 탈출용 포드를 사출했습니다!","JPN":"室長！　敵艦船が脱出用ポッドを射出しました！","ENG":"Chief! An escape pod has been released from the enemy ship!","TWN":"室長！敵人艦船的彈出逃生艙！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"함선을 버리고 도망치기로 했나 보군요. 불필요한 수고는 덜었네요.","JPN":"艦船を捨てて逃げることにしたようですね。余計な手間が省けて助かります。","ENG":"So, they've decided to abandon ship. That makes our job easier.","TWN":"看來他們是打算棄船逃跑，這樣我們也可以省點力！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"아, 아닙니다! 적의 탈출 포드가 우리 쪽으로 날아오고 있습니다!","JPN":"ち、違います！　敵の脱出ポッドがこちらに向かって飛んできます！","ENG":"Oh, no! The enemy's escape pod is flying toward us!","TWN":"不…不對！敵人的逃生艙正朝我們這邊飛過來！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"우리 쪽으로?","JPN":"こちらに？","ENG":"Toward us?","TWN":"我們這邊？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"설마…… 예전처럼 백병전이라도 벌일 셈인가?","JPN":"まさか……以前みたいに白兵戦でもするつもり？","ENG":"No way... Do they want to fight hand-to-hand, like before?","TWN":"該不會……他們是打算和之前一樣，要正面對決嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"회피 기동은 포기합니다! 다들 충격에 대비하세요!","JPN":"回避起動は諦めます！ みんな衝撃に備えてください！","ENG":"Forget evasive maneuvers. Everyone, brace for impact!","TWN":"放棄啟動迴避！全員預備迎接衝擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"……저게 뭐야.","JPN":"……何だ、あれは？","ENG":"What's that?","TWN":"……那是什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"경고! 적의 탈출 포드가 장갑을 돌파하고 함내에 침입했습니다!","JPN":"警告！　敵の脱出ポッドが装甲を突破して艦内に侵入しました！","ENG":"Warning! The enemy's escape pod penetrated our armor and landed inside!","TWN":"警告！敵人的逃生艙突破裝甲侵入艦船了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"교전 준비! 충돌 지점의 비전투원은 모두 대피시키세요!","JPN":"交戦準備！　衝突地点の非戦闘員を全員避難させてください！","ENG":"Prepare to fight! Evacuate all the noncombatants from the collision area!","TWN":"交戰準備！非戰鬥人員請盡速撤離衝突地點！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"여, 열렸다!","JPN":"あ、開いた！","ENG":"I-it's open!","TWN":"打…打開了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"뭔가 튀어나오기 전에 일단 쏴!","JPN":"何かが飛び出して来る前に撃て！","ENG":"Shoot before something comes out!","TWN":"先下手為強！射擊！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"처리했나……?","JPN":"処理できた……？","ENG":"Did we take care of it?","TWN":"都處理掉了嗎……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"제가 확인해보겠습니다, 실장님.","JPN":"私が確かめます、室長。","ENG":"Let me check, Chief.","TWN":"我確認一下，室長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"안 됩니다! 멈추세요!","JPN":"いけません！　止まってください！","ENG":"No! Stop!","TWN":"等等！不可以！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_NULL","text":{"KOREA":"네? 갑자기 왜……?","JPN":"はい？　急になぜ……？","ENG":"Sorry? Why—","TWN":"嗯？為何突然……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ALPHA_EXTRA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"환영 인사로 총알 한 다발이라니 낭만적이군.","JPN":"歓迎の挨拶が乱射だなんて、ロマンチックだな。","ENG":"Thank you for the welcoming salvo.","TWN":"用亂槍掃射來歡迎我還真是浪漫呢！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 난 총에 의지하는 것들은 질색이다.","JPN":"しかし俺は銃に依存する奴らが嫌いだ。","ENG":"But I'm sorry, I hate people who rely on guns.","TWN":"不過，我最討厭用槍的傢伙。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L25_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"힘도 없으면서 손가락에 방아쇠만 걸치면 자기가 뭐라도 되는 줄 알거든.","JPN":"実力もないくせに指に引き金さえかければ、自分がなんでもできると勘違いしやがる。","ENG":"All they do is just pull the trigger, and yet they act as if they own the power.","TWN":"不過是手指頭按個板機，就以為自己很厲害，明明是隻弱雞！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_A","text":{"KOREA":"거, 거인이다!","JPN":"きょ、巨人だ！","ENG":"G-giant!","TWN":"巨…是巨人！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ALPHA_EXTRA_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ALPHA_EXTRA_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ALPHA_EXTRA_B","text":{"KOREA":"처음 보는 강화복이야…… 해적 주제에 어디서 저런 걸……","JPN":"初めて見る強化服だ……海賊のくせにどこであんなものを……","ENG":"I've never seen a power suit like that... Where did that pirate get ahold of it?","TWN":"是沒看過的強化服……海盜怎麼會有……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ALPHA_EXTRA_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ALPHA_EXTRA_A","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"겁먹지 말고 포위하세요! 적은 한 명뿐입니다!","JPN":"怖がらず包囲してください！　敵は一人だけです！","ENG":"Stay calm and keep him surrounded! There's only one enemy!","TWN":"不要怕！把他包圍起來！敵人只有一個人而已！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L35_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그래. 벌써부터 겁먹으면 안 되지.","JPN":"そうだな。怖がるにはまだ早いぞ。","ENG":"Sure. I don't want you to be scared, yet.","TWN":"對啊，怎麼可以現在就害怕呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 아직……. 시작도 안 했으니까.","JPN":"俺はまだ……始まってもいないからな。","ENG":"Because... I haven't even... started.","TWN":"我都……還沒開始呢！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}}]`);export{e as default};